const sumTeamSolvedScore = `-- name: SumTeamSolvedScore :one
SELECT COALESCE(SUM(best.score), 0)::float8 AS score, COUNT(*)::int AS solved_count, MAX(best.submitted_at)::timestamptz AS last_solve_at
FROM (
    SELECT DISTINCT ON (problem_id) problem_id, score, submitted_at
    FROM solve_submission
    WHERE tenant_id = $1 AND contest_id = $2 AND team_id = $3 AND passed = true
    ORDER BY problem_id, score DESC, submitted_at ASC
) best
`

type SumTeamSolvedScoreParams struct {
	TenantID  int64 `json:"tenant_id"`
	ContestID int64 `json:"contest_id"`
	TeamID    int64 `json:"team_id"`
}

type SumTeamSolvedScoreRow struct {
	Score       float64            `json:"score"`
	SolvedCount int32              `json:"solved_count"`
	LastSolveAt pgtype.Timestamptz `json:"last_solve_at"`
}

func (q *Queries) SumTeamSolvedScore(ctx context.Context, arg SumTeamSolvedScoreParams) (SumTeamSolvedScoreRow, error) {
	row := q.db.QueryRow(ctx, sumTeamSolvedScore, arg.TenantID, arg.ContestID, arg.TeamID)
	var i SumTeamSolvedScoreRow
	err := row.Scan(&i.Score, &i.SolvedCount, &i.LastSolveAt)
	return i, err
}

